CREATE OR REPLACE FUNCTION public.acknowledge_inventory_alert(p_alert_id bigint, p_note text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if not (public.is_admin() or auth.role() = 'service_role') then
    raise exception 'Not authorized to acknowledge alerts.';
  end if;

  update public.inventory_alerts
  set status = 'acknowledged',
      acknowledged_at = now(),
      acknowledged_by = auth.uid(),
      note = coalesce(p_note, note)
  where id = p_alert_id
    and status in ('active', 'acknowledged');
end;
$function$
;

CREATE OR REPLACE FUNCTION public.adjust_inventory(p_product_id bigint, p_location_id bigint, p_delta_on_hand integer, p_delta_reserved integer DEFAULT 0, p_movement_type text DEFAULT 'adjustment'::text, p_reason text DEFAULT NULL::text, p_order_id bigint DEFAULT NULL::bigint, p_metadata jsonb DEFAULT NULL::jsonb)
 RETURNS TABLE(transaction_id bigint, on_hand integer, reserved integer, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_current_on_hand integer;
  v_current_reserved integer;
  v_new_on_hand integer;
  v_new_reserved integer;
  v_status text;
begin
  if not public.is_admin() then
    raise exception 'Only admins can adjust inventory.';
  end if;

  select on_hand, reserved
    into v_current_on_hand, v_current_reserved
  from public.inventory_levels
  where product_id = p_product_id
    and location_id = p_location_id
  for update;

  if v_current_on_hand is null then
    v_current_on_hand := 0;
  end if;
  if v_current_reserved is null then
    v_current_reserved := 0;
  end if;

  v_new_on_hand := v_current_on_hand + coalesce(p_delta_on_hand, 0);
  v_new_reserved := v_current_reserved + coalesce(p_delta_reserved, 0);

  if v_new_on_hand < 0 or v_new_reserved < 0 or v_new_reserved > v_new_on_hand then
    raise exception 'Invalid inventory adjustment.';
  end if;

  v_status := case when v_new_on_hand > 0 then 'available' else 'out_of_stock' end;

  insert into public.inventory_levels (
    product_id,
    location_id,
    on_hand,
    reserved,
    status
  )
  values (
    p_product_id,
    p_location_id,
    v_new_on_hand,
    v_new_reserved,
    v_status
  )
  on conflict (product_id, location_id)
  do update set
    on_hand = excluded.on_hand,
    reserved = excluded.reserved,
    status = excluded.status;

  insert into public.inventory_transactions (
    product_id,
    location_id,
    movement_type,
    delta_on_hand,
    delta_reserved,
    on_hand_before,
    on_hand_after,
    reserved_before,
    reserved_after,
    reason,
    order_id,
    created_by,
    metadata
  )
  values (
    p_product_id,
    p_location_id,
    coalesce(p_movement_type, 'adjustment'),
    coalesce(p_delta_on_hand, 0),
    coalesce(p_delta_reserved, 0),
    v_current_on_hand,
    v_new_on_hand,
    v_current_reserved,
    v_new_reserved,
    p_reason,
    p_order_id,
    auth.uid(),
    p_metadata
  )
  returning id into transaction_id;

  on_hand := v_new_on_hand;
  reserved := v_new_reserved;
  status := v_status;
  return next;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.adjust_inventory(p_product_id bigint, p_location_id bigint, p_delta_on_hand integer, p_delta_reserved integer DEFAULT 0, p_movement_type text DEFAULT 'adjustment'::text, p_reason text DEFAULT NULL::text, p_order_id bigint DEFAULT NULL::bigint, p_metadata jsonb DEFAULT NULL::jsonb, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS TABLE(transaction_id bigint, on_hand integer, reserved integer, status text)
 LANGUAGE plpgsql
