  do update set
    on_hand = excluded.on_hand,
    reserved = excluded.reserved,
    status = excluded.status;

  insert into public.inventory_transactions (
    product_id,
    location_id,
    movement_type,
    delta_on_hand,
    delta_reserved,
    on_hand_before,
    on_hand_after,
