CREATE OR REPLACE FUNCTION public.cancel_order_and_restock(p_order_id bigint)
 RETURNS public.orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_order public.orders;
begin
  if not (public.is_admin() or auth.role() = 'service_role') then
    raise exception 'Not authorized to cancel order.';
  end if;

  select *
    into v_order
  from public.orders
  where id = p_order_id
  for update;

  if not found then
    raise exception 'Order not found.';
  end if;

  if v_order.status = 'Cancelled' then
    return v_order;
  end if;

  if v_order.status not in ('Pending Payment', 'New', 'Cooking', 'Delivering') then
    raise exception 'Order cannot be cancelled from status %', v_order.status;
  end if;

  perform public.restock_inventory_for_order(p_order_id);

  update public.orders
    set status = 'Cancelled'
  where id = p_order_id
  returning * into v_order;

  return v_order;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_inventory_alerts(p_location_id bigint DEFAULT NULL::bigint)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_inserted integer := 0;
begin
  if not (public.is_admin() or auth.role() = 'service_role') then
    raise exception 'Not authorized to generate alerts.';
  end if;

  -- Resolve alerts where stock is back above reorder point.
  update public.inventory_alerts a
  set status = 'resolved',
      resolved_at = now()
  from public.inventory_levels l
  join public.reorder_rules r
    on r.product_id = l.product_id
   and r.location_id = l.location_id
   and r.is_active
  where a.product_id = l.product_id
    and a.location_id = l.location_id
    and a.alert_type = 'low_stock'
    and a.status in ('active', 'acknowledged')
    and (l.on_hand - l.reserved) > r.reorder_point
    and (p_location_id is null or l.location_id = p_location_id);

  insert into public.inventory_alerts (
    product_id,
    location_id,
    alert_type,
    severity,
    status,
    on_hand,
    reserved,
    available,
    reorder_point,
    safety_stock,
    note,
    metadata
  )
  select
    l.product_id,
    l.location_id,
    'low_stock',
    case
      when (l.on_hand - l.reserved) <= r.safety_stock then 'critical'
      else 'warning'
    end,
    'active',
    l.on_hand,
    l.reserved,
    (l.on_hand - l.reserved) as available,
    r.reorder_point,
    r.safety_stock,
    'Reorder point reached',
    jsonb_build_object(
      'lead_time_days',
      coalesce(nullif(r.lead_time_days, 0), s.lead_time_days, 0)
    )
  from public.inventory_levels l
  join public.reorder_rules r
    on r.product_id = l.product_id
   and r.location_id = l.location_id
   and r.is_active
  left join public.suppliers s
    on s.id = r.supplier_id
  where (l.on_hand - l.reserved) <= r.reorder_point
    and (p_location_id is null or l.location_id = p_location_id)
    and not exists (
      select 1
      from public.inventory_alerts a
      where a.product_id = l.product_id
        and a.location_id = l.location_id
        and a.alert_type = 'low_stock'
        and a.status in ('active', 'acknowledged')
    );

  get diagnostics v_inserted = row_count;
  return v_inserted;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.is_admin()
 RETURNS boolean
 LANGUAGE sql
 STABLE
AS $function$
  select exists (
    select 1
    from public.profiles p
    where p.id = auth.uid()
      and lower(p."group") = 'admin'
  );
$function$
;

CREATE OR REPLACE FUNCTION public.reserve_inventory_for_order(p_order_id bigint, p_location_id bigint DEFAULT NULL::bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_location_id bigint;
  v_user_id uuid;
  v_item record;
  v_on_hand integer;
  v_reserved integer;
  v_new_on_hand integer;
begin
  if not (public.is_admin() or auth.role() = 'service_role') then
    raise exception 'Not authorized to reserve inventory.';
  end if;

  if exists (
    select 1
    from public.inventory_transactions
    where order_id = p_order_id
      and movement_type = 'sale'
  ) then
    return;
  end if;

  select user_id
    into v_user_id
  from public.orders
  where id = p_order_id;

  select coalesce(
    p_location_id,
    (
      select id
      from public.inventory_locations
      where is_active = true
      order by id
      limit 1
    )
  )
  into v_location_id;

  if v_location_id is null then
    raise exception 'No active inventory location available.';
  end if;

  for v_item in
    select product_id, quantity
    from public.order_items
    where order_id = p_order_id
  loop
    select on_hand, reserved
      into v_on_hand, v_reserved
    from public.inventory_levels
    where product_id = v_item.product_id
      and location_id = v_location_id
    for update;

    if v_on_hand is null then
      v_on_hand := 0;
    end if;
    if v_reserved is null then
      v_reserved := 0;
    end if;

    v_new_on_hand := v_on_hand - v_item.quantity;
    if v_new_on_hand < 0 then
      raise exception 'Insufficient stock for product %', v_item.product_id;
    end if;

    insert into public.inventory_levels (
      product_id,
      location_id,
      on_hand,
      reserved,
      status
    )
    values (
      v_item.product_id,
      v_location_id,
      v_new_on_hand,
      v_reserved,
      case when v_new_on_hand > 0 then 'available' else 'out_of_stock' end
    )
    on conflict (product_id, location_id)
    do update set
      on_hand = excluded.on_hand,
      reserved = excluded.reserved,
      status = excluded.status;

    insert into public.inventory_transactions (
      product_id,
      location_id,
      movement_type,
      delta_on_hand,
      delta_reserved,
      on_hand_before,
      on_hand_after,
      reserved_before,
      reserved_after,
      reason,
      order_id,
      created_by,
      metadata
    )
    values (
      v_item.product_id,
      v_location_id,
      'sale',
      -v_item.quantity,
      0,
      v_on_hand,
      v_new_on_hand,
      v_reserved,
      v_reserved,
      'Order placed',
      p_order_id,
      v_user_id,
      jsonb_build_object('source', 'order')
    );
  end loop;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.restock_inventory_for_order(p_order_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_item record;
  v_on_hand integer;
  v_reserved integer;
  v_new_on_hand integer;
  v_new_reserved integer;
  v_user_id uuid;
begin
  if not (public.is_admin() or auth.role() = 'service_role') then
    raise exception 'Not authorized to restock inventory.';
  end if;

  if exists (
    select 1
    from public.inventory_transactions
    where order_id = p_order_id
      and movement_type = 'return'
  ) then
    return;
  end if;

  select user_id
    into v_user_id
  from public.orders
  where id = p_order_id;

  for v_item in
    select product_id,
           location_id,
           sum(delta_on_hand) as delta_on_hand,
           sum(delta_reserved) as delta_reserved
    from public.inventory_transactions
    where order_id = p_order_id
      and movement_type = 'sale'
    group by product_id, location_id
  loop
    select on_hand, reserved
      into v_on_hand, v_reserved
    from public.inventory_levels
    where product_id = v_item.product_id
      and location_id = v_item.location_id
    for update;

    if v_on_hand is null then
      v_on_hand := 0;
    end if;
    if v_reserved is null then
      v_reserved := 0;
    end if;

    v_new_on_hand := v_on_hand - v_item.delta_on_hand;
    v_new_reserved := v_reserved - v_item.delta_reserved;

    if v_new_on_hand < 0 or v_new_reserved < 0 or v_new_reserved > v_new_on_hand then
      raise exception 'Invalid restock adjustment for product %', v_item.product_id;
    end if;

    update public.inventory_levels
      set on_hand = v_new_on_hand,
          reserved = v_new_reserved,
          status = case when v_new_on_hand > 0 then 'available' else 'out_of_stock' end
    where product_id = v_item.product_id
      and location_id = v_item.location_id;

    insert into public.inventory_transactions (
      product_id,
      location_id,
      movement_type,
      delta_on_hand,
      delta_reserved,
      on_hand_before,
      on_hand_after,
      reserved_before,
      reserved_after,
      reason,
      order_id,
      created_by,
      metadata
    )
    values (
      v_item.product_id,
      v_item.location_id,
      'return',
      -v_item.delta_on_hand,
      -v_item.delta_reserved,
      v_on_hand,
      v_new_on_hand,
      v_reserved,
      v_new_reserved,
      'Order cancelled',
      p_order_id,
      v_user_id,
      jsonb_build_object('source', 'order')
    );
  end loop;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.touch_inventory_levels_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
